import json
import anthropic

client = anthropic.Anthropic()

JUDGE_PROMPT = """You are an expert evaluator. Score the following response against the rubric.

Task: {task}
Input: {input}
Expected criteria: {criteria}
Actual response: {response}

Evaluate the response and return a JSON object with:
  "score": <float 0.0 to 1.0>
  "reasoning": <one sentence explanation>

Respond ONLY with the JSON object."""


def llm_judge(task: str, input_text: str, criteria: str, response: str) -> dict:
    prompt = JUDGE_PROMPT.format(
        task=task,
        input=input_text,
        criteria=criteria,
        response=response,
    )
    result = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        messages=[{"role": "user", "content": prompt}],
    )
    raw = result.content[0].text.strip()
    return json.loads(raw)


def evaluate_suite(task: str, test_cases: list[dict], generate_fn) -> float:
    scores = []
    for case in test_cases:
        output = generate_fn(case["input"])
        judgment = llm_judge(
            task=task,
            input_text=case["input"],
            criteria=case["criteria"],
            response=output,
        )
        score = judgment["score"]
        scores.append(score)
        status = "PASS" if score >= 0.7 else "FAIL"
        print(f"[{status}] score={score:.2f} | {judgment['reasoning']}")

    mean_score = sum(scores) / len(scores)
    print(f"\nMean score: {mean_score:.3f}")
    return mean_score


# Example usage
SUMMARIZATION_CASES = [
    {
        "input": "The quarterly revenue grew 12% year-over-year, driven by strong cloud adoption...",
        "criteria": "Captures the key financial metric and primary driver in one concise sentence",
    },
    {
        "input": "Three patients presented with acute abdominal pain; CT imaging revealed...",
        "criteria": "Summarizes clinical presentation and findings without hallucinating details",
    },
]

if __name__ == "__main__":
    def dummy_summarize(text: str) -> str:
        return text[:80] + "..."

    evaluate_suite("Summarize the text in one sentence", SUMMARIZATION_CASES, dummy_summarize)

# Regression-detection CI script
import sys
import json
from pathlib import Path
import anthropic

THRESHOLD = 0.88  # Must not regress below this
BASELINE_FILE = Path("baselines/classifier_v3.json")

client = anthropic.Anthropic()


def load_test_suite() -> list[dict]:
    with open("test_suite/routing_tickets.json") as f:
        return json.load(f)


def run_classifier(prompt_path: str, cases: list[dict]) -> dict:
    with open(prompt_path) as f:
        system_prompt = f.read()

    correct = 0
    per_category: dict[str, list[bool]] = {}

    for case in cases:
        resp = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=32,
            system=system_prompt,
            messages=[{"role": "user", "content": case["text"]}],
        )
        predicted = resp.content[0].text.strip()
        ok = predicted == case["label"]
        correct += ok
        per_category.setdefault(case["label"], []).append(ok)

    cat_accuracy = {cat: sum(v) / len(v) for cat, v in per_category.items()}
    return {"overall": correct / len(cases), "per_category": cat_accuracy}


def check_regression(current: dict, baseline: dict) -> list[str]:
    issues = []
    if current["overall"] < baseline["overall"] - 0.01:
        issues.append(
            f"Overall accuracy regressed: {baseline['overall']:.3f} -> {current['overall']:.3f}"
        )
    for cat, base_score in baseline["per_category"].items():
        cur_score = current["per_category"].get(cat, 0.0)
        if cur_score < base_score - 0.05:
            issues.append(f"Category '{cat}' regressed: {base_score:.3f} -> {cur_score:.3f}")
    return issues


if __name__ == "__main__":
    cases = load_test_suite()
    current = run_classifier("prompts/classifier.txt", cases)
    baseline = json.loads(BASELINE_FILE.read_text())

    regressions = check_regression(current, baseline)
    if regressions:
        print("REGRESSION DETECTED:")
        for r in regressions:
            print(f"  - {r}")
        sys.exit(1)

    if current["overall"] < THRESHOLD:
        print(f"Score {current['overall']:.3f} below threshold {THRESHOLD}")
        sys.exit(1)

    print(f"All checks passed. Score: {current['overall']:.3f}")
    sys.exit(0)
